11239   auto SplitLHS = SplitIntoInitAndPostInc(MDL, LHS);
11240   // if LHS contains unknown non-invariant SCEV then bail out.
11241   if (SplitLHS.first == getCouldNotCompute())
11242     return false;
11243   assert (SplitLHS.second != getCouldNotCompute() && "Unexpected CNC");
