11245   auto SplitRHS = SplitIntoInitAndPostInc(MDL, RHS);
11246   // if RHS contains unknown non-invariant SCEV then bail out.
11247   if (SplitRHS.first == getCouldNotCompute())
11248     return false;
11249   assert (SplitRHS.second != getCouldNotCompute() && "Unexpected CNC");
11250   // It is possible that init SCEV contains an invariant load but it does
11251   // not dominate MDL and is not available at MDL loop entry, so we should
11252   // check it here.
11253   if (!isAvailableAtLoopEntry(SplitLHS.first, MDL) ||
11254       !isAvailableAtLoopEntry(SplitRHS.first, MDL))
11255     return false;
