11257   // It seems backedge guard check is faster than entry one so in some cases
11258   // it can speed up whole estimation by short circuit
11259   return isLoopBackedgeGuardedByCond(MDL, Pred, SplitLHS.second,
11260                                      SplitRHS.second) &&
11261          isLoopEntryGuardedByCond(MDL, Pred, SplitLHS.first, SplitRHS.first);
