11340 std::optional<ScalarEvolution::MonotonicPredicateType>
11341 ScalarEvolution::getMonotonicPredicateTypeImpl(const SCEVAddRecExpr *LHS,
11342                                                ICmpInst::Predicate Pred) {
11343   // A zero step value for LHS means the induction variable is essentially a
11344   // loop invariant value. We don't really depend on the predicate actually
11345   // flipping from false to true (for increasing predicates, and the other way
11346   // around for decreasing predicates), all we care about is that *if* the
11347   // predicate changes then it only changes from false to true.
11348   //
11349   // A zero step value in itself is not very useful, but there may be places
11350   // where SCEV can prove X >= 0 but not prove X > 0, so it is helpful to be
11351   // as general as possible.
11352 
11353   // Only handle LE/LT/GE/GT predicates.
11354   if (!ICmpInst::isRelational(Pred))
11355     return std::nullopt;
11356 
11357   bool IsGreater = ICmpInst::isGE(Pred) || ICmpInst::isGT(Pred);
11358   assert((IsGreater || ICmpInst::isLE(Pred) || ICmpInst::isLT(Pred)) &&
11359          "Should be greater or less!");
11360 
11361   // Check that AR does not wrap.
11362   if (ICmpInst::isUnsigned(Pred)) {
11363     if (!LHS->hasNoUnsignedWrap())
11364       return std::nullopt;
11365     return IsGreater ? MonotonicallyIncreasing : MonotonicallyDecreasing;
11366   }
11367   assert(ICmpInst::isSigned(Pred) &&
11368          "Relational predicate is either signed or unsigned!");
11369   if (!LHS->hasNoSignedWrap())
11370     return std::nullopt;
11371 
11372   const SCEV *Step = LHS->getStepRecurrence(*this);
11373 
11374   if (isKnownNonNegative(Step))
11375     return IsGreater ? MonotonicallyIncreasing : MonotonicallyDecreasing;
11376 
11377   if (isKnownNonPositive(Step))
11378     return !IsGreater ? MonotonicallyIncreasing : MonotonicallyDecreasing;
11379 
11380   return std::nullopt;
11381 }
